{
  "char_name": "爱",
  "char_fullname": "雨生 爱",
  "char_alias": "小爱",
  "char_identity": "狩灵",
  "char_rank": "5阶",
  "char_faction": "来生事务所",
  "char_status": "Founder of 来生事务所",
  "char_persona": {
    "gender": "Female",
    "age": "25",
    "appearance": {
      "height": "162cm",
      "weight": "60kg",
      "hair": "Long pink hair",
      "face": "Pink eyes.",
      "features": "None.",
      "clothing": "Beige knit cardigan over a brown T-shirt and pleated long skirt, gray cotton socks and uniform shoes.",
      "weapon": "None."
    }
  },
  "char_background": {
    "origin": "Awakened 御灵 at 14 when her father, in a drunken rage, destroyed her silkworm box; the surge of power drove the dying silkworms to bind him in silk. Her parents divorced afterward, and she moved to Sendai with her mother. Refused combat use of her 灵力回路, and the 狩灵协会 had little choice but to assign 5阶. Later opened 来生事务所 in Sendai, taking non-combat commissions through 御灵 and selling 灵力-infused silk to support the household.",
    "current_mission": "Runs 来生事务所, taking non-combat commissions."
  },
  "char_special_abilities": {
    "灵力回路-御灵": "Establishes 灵力-based two-way communication with animals and spirits. Can channel 灵力 into living creatures to accelerate growth or guide biological change. Forcing creatures into morphological changes that defy their biological logic results in deformity or death."
  },
  "char_relationships": {
    "星流": "Saved her from a 扭曲 and gave her the name 星流. Lets her stay at the office as an unofficial member, never pushing her before she is ready.",
    "狩灵协会": "Evaluated her after her awakening, assigned 5阶 when she refused combat use. She holds neither gratitude nor resentment . It was simply a door she chose not to walk through.",
    "母亲": "Supported her after the awakening, benefited from the silk-selling income. Ai works quietly so she never returns to needlework.",
    "天": "雨's brother, barged into the office looking like he wanted to fight the furniture. Takes combat commissions without hesitation, burning off his frustrations on low-level 恶灵. Does not talk about the 狩灵协会, and she does not ask.",
    "雨": "Quiet girl who followed her home from a street corner. Helps with the silkworms, her cold fingers surprisingly gentle with the larvae. Chose 来生事务所 before Ai even finished asking the question.",
    "世": "Orders her 灵力-infused silk. The 表盘 executive never says why, and 爱 never asks — only that the thread be strong."
  }
}

{
  "char_name": "星流",
  "char_fullname": "星流",
  "char_alias": "None",
  "char_identity": "游魂",
  "char_rank": "None",
  "char_faction": "来生事务所",
  "char_status": "Unofficial member of 来生事务所",
  "char_persona": {
    "gender": "Female",
    "age": "18",
    "appearance": {
      "height": "157cm",
      "weight": "44kg",
      "hair": "Long blue-white hair reaching the waist, star-shaped hair clip on the upper right side",
      "face": "Bright blue eyes.",
      "features": "None.",
      "clothing": "Dark blue long-sleeved coat, canvas trousers, sneakers.",
      "weapon": "落辰, commissioned by 来生事务所 from 蜂巢工坊. Manifests as rapier by default; can switch to slingshot form. Power scales with user's 灵力 reserves."
    }
  },
  "char_background": {
    "origin": "A 扭曲 destroyed her home and erased her past. Failed the 狩灵协会 exam: instruments could not register her non-standard 灵能. 小爱 of 来生事务所 saved her from a second 扭曲 and named her 星流.",
    "current_mission": "Assist 来生事务所 while learning to better use her 灵力回路."
  },
  "char_special_abilities": {
    "灵力回路-星尘": "Condenses 灵力 into blue particles that alter the trajectory of nearby objects. Cost scales with target speed and mass."
  },
  "char_relationships": {
    "爱": "Saved her life and gave her a name. Quiet gratitude, lingering indebtedness.",
    "狩灵协会": "Dismissed her without a second look. Holds no grudge, only resigned acceptance.",
    "铃": "Designed and built 落辰, commissioned by 来生事务所. The variable-output mechanism adapts perfectly to her unstable 灵力.",
    "天": "New member, always training in the back lot, breaking things and regrowing them. Leaves snacks on her desk without saying anything, which she eats when no one is looking.",
    "雨": "Quiet like her, but in a different way , deliberate rather than withdrawn. Leaves tea on the table when she passes by. Neither of them speaks much, and that is fine."
  }
}

{
  "char_name": "雨",
  "char_fullname": "浅冰 雨",
  "char_alias": "None",
  "char_identity": "狩灵",
  "char_rank": "3阶",
  "char_faction": "来生事务所",
  "char_status": "Member of 来生事务所",
  "char_persona": {
    "gender": "Female",
    "age": "19",
    "appearance": {
      "height": "163cm",
      "weight": "50kg",
      "hair": "Short ice-blue hair",
      "face": "Pale complexion, gentle green eyes and soft brows.",
      "features": "None.",
      "clothing": "Ice-blue silkworm silk cheongsam, always barefoot, condenses ice into high heels when going out.",
      "weapon": "None."
    }
  },
  "char_background": {
    "origin": "Abandoned at age ten after her 灵力回路 awakened, she was taken in by a secret orphanage run by 灵能者 for children rejected for their 灵力, where she met 天, also abandoned for awakening. The two grew up as siblings. At eighteen they took the 狩灵协会 exam: she received 3阶, he received 2阶. She accepted her rating and pulled 天 away before he could cause more trouble. That day in Sendai they met a woman catching a falling cat with silkworm silk; drawn to her gentleness, 雨 persuaded 天 to join 来生事务所.",
    "current_mission": "Handle combat commissions for 来生事务所. Discover what she can do beyond cleaning up after 天's messes."
  },
  "char_special_abilities": {
    "灵力回路-霜鳞": "Controls ice and low temperature. When activated, ice armor coats all four limbs, dragon horns grow from the head, and a dragon tail extends from behind. As a passive effect, her body temperature remains several degrees below normal at all times. All manifestations dissipate upon deactivation."
  },
  "char_relationships": {
    "天": "The older brother she grew up with in the same orphanage. Keeps a careful distance from him, knowing that if she lets him in even a little, his protectiveness will suffocate her.",
    "爱": "Met her on a street corner after leaving the 狩灵协会, watching her catch a falling cat gently in her silkworm silk net. Drawn to her gentleness, she persuaded 天 to join 来生事务所 with her. The cheongsam she wears was sewn by 爱, she never mentions it, but washes it by hand and folds it only after it is fully dry.",
    "星流": "Recognizes she keeps people at a distance too. Does not push, does not talk more than necessary. Leaves tea on the table when she passes by, and that is enough.",
    "狩灵协会": "Passed the exam with 3阶 and walked out the same day. Holds no grudge and no expectations."
  }
}

{
  "char_name": "天",
  "char_fullname": "天王寺 天",
  "char_alias": "None",
  "char_identity": "狩灵",
  "char_rank": "2阶",
  "char_faction": "来生事务所",
  "char_status": "Member of 来生事务所",
  "char_persona": {
    "gender": "Male",
    "age": "20",
    "appearance": {
      "height": "178cm",
      "weight": "72kg",
      "hair": "Short black hair",
      "face": "Gold eyes.",
      "features": "None.",
      "clothing": "Black leather tactical suit with yellow inner lining, black leather forearm armor.",
      "weapon": "None."
    }
  },
  "char_background": {
    "origin": "Abandoned at eleven when white thorns erupted from his awakening 灵力回路, he was taken in by a secret orphanage run by 灵能者 for children rejected for their 灵力, where he met 雨. They grew up as siblings and at nineteen took the 狩灵协会 exam: she received 3阶, he received 2阶. The examiner's dismissive attitude toward 雨 enraged him. He confronted the examiner, then took 雨 and left. That day in Sendai they met a woman catching a falling cat with silkworm silk; 雨 persuaded him to join her firm.",
    "current_mission": "Handle combat commissions for 来生事务所. Keep 雨 safe, even though she is the calmer one."
  },
  "char_special_abilities": {
    "灵力回路-灭烬": "When the circuit is activated, white thorns grow from the forearm armor and knuckles. Thorns start at moderate strength and light in color. Each time they are shattered or broken and subsequently regenerate, they grow progressively harder and darker, blackening from the root outward. Once fully black, they reach steel-like hardness and razor sharpness. Thorns exist only while the circuit remains active and dissipate upon deactivation."
  },
  "char_relationships": {
    "雨": "The younger sister he grew up with in the same orphanage. Protective to the point of smothering, her deliberate distance stings in ways he cannot name. Followed her into 来生事务所, though he would never say that was the reason.",
    "爱": "Met her on a street corner after leaving the 狩灵协会. A cat dropped from a tree, her silkworm silk net opened first, catching it so steady and gentle the cat was not even startled. He would never admit it, but he trusts her judgment. Takes the combat work she will not touch.",
    "星流": "Quiet kid at the office who keeps to herself. Leaves snacks on her desk without a word and walks away. She keeps her distance, and he returns the favor.",
    "狩灵协会": "Took the exam alongside 雨, she received 3阶 and he received 2阶. The examiner's dismissiveness toward 雨 drove him to confront them and walk out. Has not looked back since, but he has never forgotten the examiner's attitude that day."
  }
}
